export const callAI = async (userMessage, systemPrompt) => {
  if (!import.meta.env.VITE_AI_PROXY_URL) throw new Error('AI_NOT_CONFIGURED');
  if (!navigator.onLine) throw new Error('OFFLINE');
  let response;
  try {
    response = await fetch(import.meta.env.VITE_AI_PROXY_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: import.meta.env.VITE_AI_MODEL || 'claude-sonnet-4-20250514',
        max_tokens: parseInt(import.meta.env.VITE_AI_MAX_TOKENS || '2048'),
        system: systemPrompt,
        messages: [{ role: 'user', content: userMessage }]
      })
    });
  } catch (e) {
    if (e instanceof TypeError) throw new Error('NETWORK_ERROR');
    throw e;
  }
  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err?.error?.message || `HTTP ${response.status}`);
  }
  return (await response.json()).content[0].text;
};

const AI_ERRORS = {
  AI_NOT_CONFIGURED: 'AI not configured — set VITE_AI_PROXY_URL in .env.local.',
  OFFLINE: 'No internet connection.',
  NETWORK_ERROR: 'Network error — check your connection.'
};
export const getAIErrorMessage = (err) => AI_ERRORS[err.message] || 'AI error: ' + err.message;

getNeighborIds.implementation:
export function getNeighborIds(nodeId, depth, links) {
  const visited = new Set([nodeId]);
  let frontier = new Set([nodeId]);
  for (let d = 0; d < depth; d++) {
    const next = new Set();
    links.forEach(l => {
      if (frontier.has(l.source) && !visited.has(l.target)) next.add(l.target);
      if (frontier.has(l.target) && !visited.has(l.source)) next.add(l.source);
    });
    next.forEach(id => visited.add(id));
    frontier = next;
  }
  visited.delete(nodeId); // exclude the main node itself
  return visited;
}

