quiz.response_parsing:
export const parseQuizResponse = (raw) => {
  const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();
  let parsed;
  try { parsed = JSON.parse(cleaned); } catch(e) { throw new Error('Invalid JSON: '+e.message); }
  if (!Array.isArray(parsed)) throw new Error('Not an array');
  parsed.forEach((q, i) => {
    if (typeof q.question !== 'string' || !q.question.trim()) throw new Error(`Q${i}: missing question`);
    if (!Array.isArray(q.options) || q.options.length !== 4) throw new Error(`Q${i}: need 4 options`);
    if (typeof q.correct_answer !== 'number' || q.correct_answer < 0 || q.correct_answer > 3)
      throw new Error(`Q${i}: correct_answer must be 0–3`);
    if (typeof q.explanation !== 'string') throw new Error(`Q${i}: missing explanation`);
  });
  return parsed;
};

sm2_algorithm.implementation:
export function sm2(score, easeFactor, interval) {
  const ef = (typeof easeFactor === 'number' && !isNaN(easeFactor)) ? easeFactor : 2.5;
  const iv = (typeof interval === 'number' && !isNaN(interval) && interval > 0) ? interval : 1;
  const q = Math.round(score * 5);
  let newEF = Math.max(1.3, parseFloat((ef + 0.1 - (5-q)*(0.08+(5-q)*0.02)).toFixed(2)));
  const newInterval = q < 3 ? 1 : iv === 1 ? 6 : Math.round(iv * newEF);
  const next = new Date();
  next.setDate(next.getDate() + newInterval);
  return { newEF, newInterval, nextReview: next.toISOString().split('T')[0] };
}

